function solve(edges, online, k) {
    const n = online.length;
    if (n === 0) {
        return -1;
    }
    if (edges.length === 0) {
        return -1;
    }

    let maxC = -1;
    for (let edge of edges) {
        if (edge[2] > maxC) {
            maxC = edge[2];
        }
    }

    const check = (x) => {
        let allowed = new Array(n);
        for (let i = 0; i < n; i++) {
            if (i === 0 || i === n-1) {
                allowed[i] = true;
            } else {
                allowed[i] = online[i];
            }
        }

        let graph = Array.from({ length: n }, () => []);
        let inDegree = new Array(n).fill(0);

        for (let edge of edges) {
            const [u, v, w] = edge;
            if (v === 0) continue;
            if (u === n-1) continue;
            if (w < x) continue;
            if (!allowed[u] || !allowed[v]) continue;

            graph[u].push([v, w]);
            inDegree[v]++;
        }

        let dist = new Array(n).fill(Number.MAX_SAFE_INTEGER);
        dist[0] = 0;

        let queue = [];
        let front = 0;
        for (let i = 0; i < n; i++) {
            if (inDegree[i] === 0 && allowed[i]) {
                queue.push(i);
            }
        }

        while (front < queue.length) {
            let u = queue[front];
            front++;
            for (const [v, w] of graph[u]) {
                const newCost = dist[u] + w;
                if (newCost < dist[v]) {
                    dist[v] = newCost;
                }
                inDegree[v]--;
                if (inDegree[v] === 0) {
                    queue.push(v);
                }
            }
        }

        return dist[n-1] <= k;
    };

    let low = 0;
    let high = maxC;
    let ans = -1;
    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
